                      key={type}
                      htmlFor={`template-${type}`}
                      className="flex flex-col items-center gap-2 rounded-md border p-4 cursor-pointer hover-elevate text-center [&:has(:checked)]:border-primary [&:has(:checked)]:bg-primary/5"
