                      <input
                        type="radio"
                        id={`template-${type}`}
                        name="templateType"
                        value={type}
                        checked={formData.templateType === type}
                        onChange={() =>
                          setFormData({ ...formData, templateType: type })
                        }
                        className="sr-only"
                        data-testid={`radio-template-${type}`}
                      />
