                      <span className="text-sm font-medium">
                        {templateTypeLabels[type]}
                      </span>
                    </Label>
                  ))}
                </div>
              </CardContent>
            </Card>

            <DocumentEditor
              templateType={formData.templateType}
              onSave={(sections) => {
                toast({ title: "文档已保存" });
              }}
            />
          </div>
        );

      case 5:
        return (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-2 space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <CheckCircle className="h-5 w-5 text-green-500" />
                    最终合规检查
                  </CardTitle>
                  <CardDescription>
                    请确保所有项目都已通过检查，方可导出申请包
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <ComplianceChecklist results={complianceResults} />
                </CardContent>
              </Card>

              <ExportPreview
                projectName={formData.name || "项目名称"}
                version={formData.version}
              />
            </div>

            <div className="space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">导出选项</CardTitle>
                </CardHeader>
                <CardContent className="space-y-3">
                  <Button className="w-full" data-testid="button-export-zip">
                    <Download className="h-4 w-4 mr-2" />
                    导出 ZIP 包
                  </Button>
                  <Button
                    variant="outline"
                    className="w-full"
                    data-testid="button-print-guide"
                  >
                    生成打印指南
                  </Button>
                  <Button
                    variant="outline"
                    className="w-full"
                    data-testid="button-field-mapping"
                  >
                    查看网报对照表
                  </Button>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle className="text-base">打印说明</CardTitle>
                </CardHeader>
                <CardContent className="text-sm text-muted-foreground space-y-2">
                  <p>• 使用 A4 纸张打印</p>
                  <p>• 源代码材料单面打印</p>
                  <p>• 说明书可双面打印</p>
                  <p>• 签章位预留于指定页面底部</p>
                </CardContent>
              </Card>
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div className="p-6 space-y-6">
      <PageHeader
        title={isNew ? "创建新项目" : formData.name || "项目详情"}
        breadcrumbs={[
          { label: "项目列表", href: "/" },
          { label: isNew ? "新建项目" : formData.name || "项目" },
        ]}
      />

      <StepIndicator currentStep={currentStep} className="mb-8" />

      {renderStepContent()}

      <div className="fixed bottom-0 left-0 right-0 border-t bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60 p-4 z-50">
        <div className="max-w-7xl mx-auto flex items-center justify-between gap-4">
          <Button
            variant="outline"
            onClick={() => saveSoftwareInfoMutation.mutate()}
            disabled={isNew}
            data-testid="button-save-draft"
          >
            <Save className="h-4 w-4 mr-2" />
            保存草稿
          </Button>

          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              onClick={handlePrev}
              disabled={currentStep === 1}
              data-testid="button-prev-step"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              上一步
            </Button>
            <Button
              onClick={handleNext}
              disabled={
                createProjectMutation.isPending || updateProjectMutation.isPending
              }
              data-testid="button-next-step"
            >
              {currentStep === 5 ? (
                <>
                  <Download className="h-4 w-4 mr-2" />
                  导出
                </>
              ) : (
                <>
                  下一步
                  <ArrowRight className="h-4 w-4 ml-2" />
                </>
              )}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

